+import { z } from 'zod';

-// AI SDK compatible
-const partial = vj.parsePartialJson('{"a": 1, "b": ');
-// { value: { a: 1, b: null }, state: "repaired-parse" }
+const ToolCall = z.object({ name: z.string(), args: z.record(z.unknown()) });
